esqlQuery.esql:
FROM metrics-traefik.otel-*
// Limit to process FD metrics
| WHERE process_open_fds IS NOT NULL AND process_max_fds IS NOT NULL
// Take latest values (gauges)
| STATS open_fds = MAX(process_open_fds), max_fds = MAX(process_max_fds)
// Compute utilisation; alert when > 80% (tune as needed)
| EVAL fd_pct = ROUND(open_fds / max_fds * 100.0, 2)
| WHERE fd_pct > 80.0
